def route_nyc(t,x):
    """
    This function models traffic data along a given route.
    The function returns the expected speed at a given time t 
    and position x along the route. The model is based on 
    historical traffic data on a number of road links provided 
    by NYC OpenData.
    
    Parameters:
      0 <= t <= 24 (hour of day)
      0 <= x <= 60 (km from start of route)
    Returns:
      Speed in km/h    
    """
    return pchip_2d(data_t,data_x,nyc_velocity,t,x)-10

### PART 4A ###
def nyc_route_traveler_euler(t0,h):
    time_list = [t0]
    x_list = [0.0]
    v_list = []

    tmax = 24
    xmax = 60
    while time_list[-1] < tmax and x_list[-1] < xmax:

        t = time_list[-1]
        x = x_list[-1]
        v = float(route_nyc(t, x))

        # Spara hastigheten i nuvarande punkt
        v_list.append(v)

        # Eulersteg
        t_next = t + h
        x_next = x + h * v

        # Om vi passerar 60 km – korta sista steget
        if x_next >= 60:
            h_last = (60 - x) / v
            t_next = t + h_last
            x_next = 60

            time_list.append(t_next)
            x_list.append(x_next)
            v_list.append(float(route_nyc(t_next, x_next)))
            break

        time_list.append(t_next)
        x_list.append(x_next)

    return np.array(time_list), np.array(x_list), np.array(v_list)

